gVp(){return"\u0698\u0645\u0627\u0631\u06d5\u06cc\u06d5\u06a9\u06cc \u062f\u0631\u0648\u0633\u062a\u06cc \u06a9\u0627\u0631\u062a \u0628\u0646\u0648\u0648\u0633\u06d5 (13\u201319 \u0698\u0645\u0627\u0631\u06d5)."},
gGX(){return"\u0628\u06d5\u0631\u0648\u0627\u0631\u06ce\u06a9\u06cc \u062f\u0631\u0648\u0633\u062a\u06cc \u062f\u0627\u0647\u0627\u062a\u0648\u0648 \u0628\u0646\u0648\u0648\u0633\u06d5 (MM/YY)."},
gVn(){return"\u06a9\u06c6\u062f\u06ce\u06a9\u06cc \u062f\u0631\u0648\u0633\u062a\u06cc CVV \u0628\u0646\u0648\u0648\u0633\u06d5 (3\u20134 \u0698\u0645\u0627\u0631\u06d5)."},
gVy(){return"\u06a9\u0627\u0631\u062a\u06d5\u06a9\u06d5 \u067e\u0627\u0634\u06d5\u06a9\u06d5\u0648\u062a \u0646\u06d5\u06a9\u0631\u0627. \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5."},
gVB(){return"\u0628\u0686\u06c6 \u0698\u0648\u0648\u0631\u06d5\u0648\u06d5 \u0628\u06c6 \u0632\u06cc\u0627\u062f\u06a9\u0631\u062f\u0646\u06cc \u0634\u06ce\u0648\u0627\u0632\u06cc \u067e\u0627\u0631\u06d5\u062f\u0627\u0646"},
gVA(){return"\u06a9\u0627\u0631\u062a\u06d5 \u067e\u0627\u0634\u06d5\u06a9\u06d5\u0648\u062a\u06a9\u0631\u0627\u0648\u06d5\u06a9\u0627\u0646\u062a \u0644\u06d5\u06af\u06d5\u06b5 \u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5\u062a \u0644\u06d5\u0633\u06d5\u0631 \u0647\u06d5\u0645\u0648\u0648 \u0626\u0627\u0645\u06ce\u0631\u06ce\u06a9 \u062f\u06d5\u0628\u0646."},
gVZ(){return"\u062a\u0627\u06cc\u0628\u06d5\u062a\u0645\u06d5\u0646\u062f\u06cc \u0648 \u0626\u0627\u0633\u0627\u06cc\u0634"},
gVY(){return"\u0626\u0627\u0633\u0627\u06cc\u0634"},
gVL(){return"\u0642\u0648\u0641\u06b5\u06cc \u0626\u06d5\u067e \u0628\u06d5 \u067e\u06d5\u0646\u062c\u06d5\u0645\u06c6\u0631"},
gVN(){return"\u062f\u0627\u0648\u0627\u06a9\u0631\u062f\u0646\u06cc \u0646\u0627\u0633\u06cc\u0646\u06d5\u0648\u06d5\u06cc \u0695\u0648\u062e\u0633\u0627\u0631 / \u067e\u06d5\u0646\u062c\u06d5\u0645\u06c6\u0631 \u0628\u06c6 \u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u06cc \u0626\u06d5\u067e"},
gW_(){return"\u0633\u06d5\u0644\u0645\u0627\u0646\u062f\u0646\u06cc \u062f\u0648\u0648 \u0647\u06d5\u0646\u06af\u0627\u0648\u06cc"},
gW0(){return"\u067e\u0634\u062a\u0695\u0627\u0633\u062a\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u06cc \u0686\u0648\u0648\u0646\u06d5\u0698\u0648\u0648\u0631\u06d5\u0648\u06d5 \u0628\u06d5 \u06a9\u06c6\u062f\u06cc \u062a\u0627\u06a9 \u0628\u06d5\u06a9\u0627\u0631\u0647\u06ce\u0646\u0627\u0646"},
